// Access trigger body field safely
@{triggerBody()?['customer']?['email']}

// Concatenate strings
@{concat('Order-', triggerBody()?['orderId'], '-', utcNow('yyyyMMdd'))}

// XPath on XML body
@{xpath(xml(body('Get_XML_Response')), 'string(/Order/Customer/Name/text())')}

// Parse JSON string to object
@{json(body('Get_String_Response'))}

// Conditional expression
@{if(equals(triggerBody()?['status'], 'active'), 'ENABLED', 'DISABLED')}

// Base64 encode
@{base64(concat(parameters('clientId'), ':', parameters('clientSecret')))}

// Get current UTC time formatted
@{utcNow('yyyy-MM-ddTHH:mm:ssZ')}

// Array operations
@{first(body('Parse_JSON')?['items'])}
@{length(body('Parse_JSON')?['items'])}

resource logicApp 'Microsoft.Web/sites@2022-09-01' = {
  name: 'la-orderprocessing-prod'
  location: location
  kind: 'workflowapp'
  identity: {
    type: 'SystemAssigned'
  }
  properties: {
    serverFarmId: appServicePlan.id
    siteConfig: {
      appSettings: [
        {
          name: 'APP_KIND'
          value: 'workflowApp'
        }
        {
          name: 'AzureWebJobsStorage'
          value: 'DefaultEndpointsProtocol=https;AccountName=${storageAccount.name};AccountKey=${storageAccount.listKeys().keys[0].value}'
        }
        {
          name: 'WEBSITE_CONTENTAZUREFILECONNECTIONSTRING'
          value: 'DefaultEndpointsProtocol=https;AccountName=${storageAccount.name};AccountKey=${storageAccount.listKeys().keys[0].value}'
        }
        {
          name: 'FUNCTIONS_EXTENSION_VERSION'
          value: '~4'
        }
        {
          name: 'FUNCTIONS_WORKER_RUNTIME'
          value: 'node'
        }
        {
          name: 'WEBSITE_NODE_DEFAULT_VERSION'
          value: '~18'
        }
        {
          name: 'ServiceBusConnection__fullyQualifiedNamespace'
          value: '${serviceBusNamespace.name}.servicebus.windows.net'
        }
      ]
      vnetRouteAllEnabled: true
    }
    virtualNetworkSubnetId: subnet.id
  }
}
